class Coupon {
  constructor({ code, discountType, discountValue, expiresAt, maxRedemptions = 1 }) {
    this.code = code;
    this.discountType = discountType;
    this.discountValue = discountValue;
    this.expiresAt = new Date(expiresAt).getTime();
    this.maxRedemptions = maxRedemptions;
    this.redemptions = 0;
    this.usedBy = new Set();
  }

  isExpired(now = Date.now()) {
    return now > this.expiresAt;
  }

  hasUserUsed(userId) {
    return this.usedBy.has(userId);
  }

  canRedeem(userId, now = Date.now()) {
    if (this.isExpired(now)) return { ok: false, reason: 'COUPON_EXPIRED' };
    if (this.hasUserUsed(userId)) return { ok: false, reason: 'COUPON_ALREADY_USED_BY_USER' };
    if (this.redemptions >= this.maxRedemptions) return { ok: false, reason: 'COUPON_REDEMPTION_LIMIT_REACHED' };
    return { ok: true };
  }

  applyDiscount(amount) {
    if (this.discountType === 'percentage') {
      const discount = Math.min(amount, (amount * this.discountValue) / 100);
      return {
        originalAmount: amount,
        discountAmount: round2(discount),
        finalAmount: round2(amount - discount),
      };
    }

    if (this.discountType === 'fixed') {
      const discount = Math.min(amount, this.discountValue);
      return {
        originalAmount: amount,
        discountAmount: round2(discount),
        finalAmount: round2(amount - discount),
      };
    }

    throw new Error('INVALID_DISCOUNT_TYPE');
  }

  redeem(userId, amount, now = Date.now()) {
    const validation = this.canRedeem(userId, now);
    if (!validation.ok) return validation;

    this.redemptions += 1;
    this.usedBy.add(userId);

    return {
      ok: true,
      code: this.code,
      ...this.applyDiscount(amount),
      redeemedAt: now,
    };
  }
}

class Mutex {
  constructor() {
    this.locked = false;
    this.queue = [];
  }

  async acquire() {
    return new Promise(resolve => {
      if (!this.locked) {
        this.locked = true;
        resolve(this._release.bind(this));
      } else {
        this.queue.push(resolve);
      }
    });
  }

  _release() {
    if (this.queue.length > 0) {
      const next = this.queue.shift();
      next(this._release.bind(this));
    } else {
      this.locked = false;
    }
  }
}

class LockManager {
  constructor() {
    this.locks = new Map();
  }

  getLock(key) {
    if (!this.locks.has(key)) {
      this.locks.set(key, new Mutex());
    }
    return this.locks.get(key);
  }
}

class CouponStore {
  constructor() {
    this.coupons = new Map();
  }

  addCoupon(couponData) {
    const coupon = new Coupon(couponData);
    this.coupons.set(coupon.code, coupon);
    return coupon;
  }

  getCoupon(code) {
    return this.coupons.get(code) || null;
  }
}

class CouponRedemptionSystem {
  constructor() {
    this.store = new CouponStore();
    this.lockManager = new LockManager();
  }

  createCoupon(couponData) {
    return this.store.addCoupon(couponData);
  }

  async redeemCoupon({ code, userId, amount, now = Date.now() }) {
    const lock = this.lockManager.getLock(code);
    const release = await lock.acquire();

    try {
      const coupon = this.store.getCoupon(code);
      if (!coupon) {
        return { ok: false, reason: 'COUPON_NOT_FOUND' };
      }

      return coupon.redeem(userId, amount, now);
    } finally {
      release();
    }
  }
}

function round2(value) {
  return Math.round((value + Number.EPSILON) * 100) / 100;
}

